const body = $input.first().json.body ?? $input.first().json;

// Só processa mensagens recebidas (não as enviadas pelo próprio bot)
if (body.data?.key?.fromMe === true) return [];
if (body.event !== 'messages.upsert') return [];

const data = body.data;
const remoteJid = data.key?.remoteJid;
if (!remoteJid) return [];
if (remoteJid.endsWith('@g.us')) return []; // ignora grupos

// SÓ áudio interessa pra esse serviço
if (!data.message?.audioMessage) return [];

const telefone = remoteJid.replace('@s.whatsapp.net', '');

return [{
  json: {
    telefone,
    nome: data.pushName ?? 'Cliente',
    remoteJid,
    instancia: body.instance ?? 'resumo',
    // chave da mensagem — usada pra baixar o áudio na Evolution
    msgKey: {
      remoteJid,
      fromMe: false,
      id: data.key?.id ?? ''
    },
    duracao: data.message.audioMessage?.seconds ?? 0
  }
}];

const ctx = $('Normalizar Payload').first().json;
const resp = $input.first().json;

const base64 = resp.base64 ?? resp.media ?? null;
if (!base64) {
  return [{ json: { ...ctx, erroDownload: true } }];
}

let mime = resp.mimetype ?? 'audio/ogg';
mime = mime.split(';')[0].trim();

return [{
  json: { ...ctx, erroDownload: false },
  binary: {
    audio: {
      data: base64,
      mimeType: mime,
      fileName: 'audio.ogg'
    }
  }
}];

const ctx = $('Base64 → Arquivo').first().json;
const resp = $input.first().json;

const transcricao = (resp.text ?? '').trim();

if (!transcricao) {
  return [{ json: { ...ctx, transcricao: '', falhou: true } }];
}

const systemPrompt = `Você recebe a transcrição de um áudio de WhatsApp. Organize em um resumo claro e objetivo em português.

TRANSCRIÇÃO:
"${transcricao}"

Responda APENAS com um JSON neste formato:
{
  "assunto": "frase curta com o tema do áudio",
  "pontos": ["ponto 1", "ponto 2", "ponto 3"],
  "acao": "o que a pessoa precisa fazer/responder, ou 'Nenhuma ação' se for só informativo",
  "urgencia": "Alta" | "Média" | "Baixa"
}`;

return [{
  json: {
    ...ctx,
    transcricao,
    falhou: false,
    anthropicBody: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 600,
      messages: [{ role: 'user', content: systemPrompt }]
    }
  }
}];

const ctx = $('Montar Prompt Resumo').first().json;
const resp = $input.first().json;

// Caso transcrição tenha falhado lá atrás
if (ctx.falhou || ctx.erroDownload) {
  return [{ json: { ...ctx, mensagemParaCliente: '🎙️ Não consegui processar esse áudio. Pode tentar reenviar?' } }];
}

let parsed = null;
const rawText = resp.content?.[0]?.text ?? '';
try {
  parsed = JSON.parse(rawText.replace(/```json?/g, '').replace(/```/g, '').trim());
} catch (e) {
  parsed = null;
}

let msg;
if (!parsed) {
  // Fallback: manda só a transcrição
  msg = `🎙️ *Transcrição do áudio*\n\n"${ctx.transcricao}"`;
} else {
  const pontos = (parsed.pontos ?? []).map(p => `• ${p}`).join('\n');
  const urg = parsed.urgencia ?? 'Baixa';
  const emojiUrg = urg === 'Alta' ? '🔴' : urg === 'Média' ? '🟡' : '🟢';
  msg = `🎙️ *Resumo do áudio*\n\n` +
    `📌 *Assunto:* ${parsed.assunto ?? '-'}\n\n` +
    `*Pontos principais:*\n${pontos}\n\n` +
    `✅ *O que precisa:* ${parsed.acao ?? 'Nenhuma ação'}\n` +
    `${emojiUrg} *Urgência:* ${urg}\n\n` +
    `_Transcrição completa:_\n"${ctx.transcricao}"`;
}

return [{ json: { ...ctx, mensagemParaCliente: msg } }];
